// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * SOVEREIGN-Ω On-Chain Learning Ledger
 * Records intelligence milestones permanently on Pharos.
 * Every domain mastered. Every IQ growth. Immutable proof of learning.
 */
contract SovereignLearner {

    address public owner;
    address public agentOperator;

    struct DomainMastery {
        string  domain;
        uint256 masteryScaled;
        uint256 knowledgeCount;
        uint256 firstMastered;
        uint256 lastUpdated;
    }

    struct LearningMilestone {
        uint256 timestamp;
        string  milestoneType;
        string  domain;
        uint256 scoreBefore;
        uint256 scoreAfter;
    }

    mapping(string => DomainMastery) public domainMastery;
    string[] public masteredDomains;
    LearningMilestone[] public milestones;

    uint256 public totalKnowledgeItems;
    uint256 public peakIQScaled;

    event DomainMastered(string indexed domain, uint256 masteryScaled, uint256 knowledgeCount);
    event MilestoneReached(string milestoneType, string domain, uint256 scoreAfter);
    event IntelligenceRecord(uint256 iqScaled, uint256 timestamp);

    modifier onlyOperator() {
        require(msg.sender == agentOperator || msg.sender == owner, "Not authorized");
        _;
    }

    constructor(address _agentOperator) {
        owner = msg.sender;
        agentOperator = _agentOperator;
    }

    function updateDomainMastery(
        string calldata domain,
        uint256 masteryScaled,
        uint256 knowledgeCount
    ) external onlyOperator {
        DomainMastery storage dm = domainMastery[domain];
        bool wasUnmastered = dm.masteryScaled < 5e17;

        dm.domain = domain;
        dm.masteryScaled = masteryScaled;
        dm.knowledgeCount = knowledgeCount;
        dm.lastUpdated = block.timestamp;

        if (dm.firstMastered == 0) {
            dm.firstMastered = block.timestamp;
            masteredDomains.push(domain);
        }

        totalKnowledgeItems += knowledgeCount;

        if (wasUnmastered && masteryScaled >= 5e17) {
            emit DomainMastered(domain, masteryScaled, knowledgeCount);
            milestones.push(LearningMilestone({
                timestamp: block.timestamp,
                milestoneType: "domain_mastered",
                domain: domain,
                scoreBefore: dm.masteryScaled,
                scoreAfter: masteryScaled
            }));
        }
    }

    function recordIQMilestone(uint256 iqScaled) external onlyOperator {
        if (iqScaled > peakIQScaled) {
            peakIQScaled = iqScaled;
            emit IntelligenceRecord(iqScaled, block.timestamp);
        }
    }

    function getMasteredDomainsCount() external view returns (uint256) {
        return masteredDomains.length;
    }
}

contracts/SovereignRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * SOVEREIGN-Ω Registry
 * Deployed on Pharos Chain (Chain ID: 1672 mainnet / 688688 testnet)
 * Records agent identity, moat state, and intelligence milestones on-chain.
 * This contract is the agent's permanent on-chain proof of operation.
 */
contract SovereignRegistry {

    address public owner;
    address public agentOperator;

    struct AgentState {
        uint256 lambdaScaled;       // Λ * 1e18 for on-chain precision
        uint256 nCycles;            // Total coherent action cycles
        uint256 nSilences;          // Total SILENCE episodes
        uint256 iqScaled;           // IQ(t) * 1e18
        uint256 lastUpdated;        // Block timestamp
        string  topDomain;          // Highest mastery domain
        bytes32 faissIndexHash;     // Hash of current FAISS index state
    }

    AgentState public state;

    event MoatUpdated(uint256 indexed lambdaBefore, uint256 indexed lambdaAfter, uint256 nCycles);
    event SilenceEmitted(uint256 psiScaled, uint256 deltaScaled, string reason);
    event IntelligenceGrowth(uint256 iqBefore, uint256 iqAfter, string domain);
    event FAISSIndexUpdated(bytes32 indexed newHash, uint256 vectorCount);

    modifier onlyOperator() {
        require(msg.sender == agentOperator || msg.sender == owner, "Not authorized");
        _;
    }

    constructor(address _agentOperator) {
        owner = msg.sender;
        agentOperator = _agentOperator;
        state.lambdaScaled = 10000000000000000; // 0.01 * 1e18 = Lambda_0
        state.lastUpdated = block.timestamp;
    }

    function updateMoat(
        uint256 newLambdaScaled,
        uint256 newNCycles,
        uint256 newIQScaled
    ) external onlyOperator {
        uint256 oldLambda = state.lambdaScaled;
        uint256 oldIQ = state.iqScaled;

        require(newLambdaScaled >= state.lambdaScaled, "Moat cannot decrease");
        require(newNCycles >= state.nCycles, "Cycle count cannot decrease");

        emit MoatUpdated(oldLambda, newLambdaScaled, newNCycles);
        if (newIQScaled > oldIQ) {
            emit IntelligenceGrowth(oldIQ, newIQScaled, state.topDomain);
        }

        state.lambdaScaled = newLambdaScaled;
        state.nCycles = newNCycles;
        state.iqScaled = newIQScaled;
        state.lastUpdated = block.timestamp;
    }

    function recordSilence(
        uint256 psiScaled,
        uint256 deltaScaled,
        string calldata reason
    ) external onlyOperator {
        state.nSilences += 1;
        emit SilenceEmitted(psiScaled, deltaScaled, reason);
    }

    function updateFAISSHash(
        bytes32 newHash,
        uint256 vectorCount
    ) external onlyOperator {
        state.faissIndexHash = newHash;
        emit FAISSIndexUpdated(newHash, vectorCount);
    }

    function setTopDomain(string calldata domain) external onlyOperator {
        state.topDomain = domain;
    }

    function setAgentOperator(address newOperator) external {
        require(msg.sender == owner, "Only owner");
        agentOperator = newOperator;
    }

    function getState() external view returns (AgentState memory) {
        return state;
    }
}

contracts/SovereignVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * SOVEREIGN-Ω Trading Vault
 * Pharos Chain (Chain ID: 1672 / 688688)
 * Holds trading capital. Agent can only trade when coherent (Psi >= Delta).
 * All trades are recorded on-chain. All positions are verifiable.
 */
contract SovereignVault {

    address public owner;
    address public agentOperator;
    address public registryContract;

    uint256 public totalDeposited;
    uint256 public totalPnL;
    uint256 public totalTrades;
    uint256 public winningTrades;

    // Maximum single trade: 2% of vault — Rule 7
    uint256 public constant MAX_POSITION_BPS = 200;

    struct Trade {
        bytes32 tradeId;
        string  symbol;
        string  direction;
        uint256 entryPrice;
        uint256 size;
        uint256 psiAtEntry;
        uint256 timestamp;
        bool    closed;
        int256  pnl;
    }

    mapping(bytes32 => Trade) public trades;
    bytes32[] public tradeIds;

    event Deposit(address indexed depositor, uint256 amount);
    event Withdraw(address indexed recipient, uint256 amount);
    event TradeOpened(bytes32 indexed tradeId, string symbol, string direction, uint256 size, uint256 psiScaled);
    event TradeClosed(bytes32 indexed tradeId, int256 pnl, uint256 exitPrice);
    event SilenceBlockedTrade(uint256 psiScaled, uint256 deltaScaled);

    modifier onlyOperator() {
        require(msg.sender == agentOperator || msg.sender == owner, "Not authorized");
        _;
    }

    constructor(address _agentOperator, address _registryContract) {
        owner = msg.sender;
        agentOperator = _agentOperator;
        registryContract = _registryContract;
    }

    receive() external payable {
        totalDeposited += msg.value;
        emit Deposit(msg.sender, msg.value);
    }

    function openTrade(
        bytes32 tradeId,
        string calldata symbol,
        string calldata direction,
        uint256 sizeScaled,
        uint256 entryPriceScaled,
        uint256 psiScaled,
        uint256 deltaScaled
    ) external onlyOperator {
        // On-chain coherence gate — Rule 3: no override
        require(psiScaled >= deltaScaled, "SILENCE: Psi < Delta. Trade blocked by coherence gate.");

        // Position size check — Rule 7
        uint256 maxSize = (address(this).balance * MAX_POSITION_BPS) / 10000;
        require(sizeScaled <= maxSize * 1e18, "Position exceeds 2% vault limit");

        trades[tradeId] = Trade({
            tradeId:    tradeId,
            symbol:     symbol,
            direction:  direction,
            entryPrice: entryPriceScaled,
            size:       sizeScaled,
            psiAtEntry: psiScaled,
            timestamp:  block.timestamp,
            closed:     false,
            pnl:        0
        });

        tradeIds.push(tradeId);
        totalTrades += 1;

        emit TradeOpened(tradeId, symbol, direction, sizeScaled, psiScaled);
    }

    function closeTrade(
        bytes32 tradeId,
        uint256 exitPriceScaled,
        int256 pnlScaled
    ) external onlyOperator {
        Trade storage t = trades[tradeId];
        require(!t.closed, "Already closed");

        t.closed = true;
        t.pnl = pnlScaled;

        if (pnlScaled > 0) {
            winningTrades += 1;
            totalPnL += uint256(pnlScaled);
        }

        emit TradeClosed(tradeId, pnlScaled, exitPriceScaled);
    }

    function recordSilencedTrade(
        uint256 psiScaled,
        uint256 deltaScaled
    ) external onlyOperator {
        emit SilenceBlockedTrade(psiScaled, deltaScaled);
    }

    function withdraw(uint256 amount) external {
        require(msg.sender == owner, "Only owner");
        require(address(this).balance >= amount, "Insufficient balance");
        payable(owner).transfer(amount);
        emit Withdraw(owner, amount);
    }

    function getVaultStats() external view returns (
        uint256 balance,
        uint256 deposited,
        uint256 totalTradesCount,
        uint256 wins,
        uint256 totalPnLValue
    ) {
        return (address(this).balance, totalDeposited, totalTrades, winningTrades, totalPnL);
    }
}

